    after = json.load(f)

def pkg_map(projects):
    result = {}
    for p in projects:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            key = (name, fw['framework'])
            for pkg in fw['topLevelPackages']:
                result[(key[0], key[1], pkg['id'])] = pkg['resolvedVersion']
    return result

b = pkg_map(baseline['projects'])
a = pkg_map(after['projects'])

